import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { openKv } from "https://deno.land/x/denokv/mod.ts";

const kv = await openKv();

serve(async (req) => {
  if (req.method === "GET") {
    const url = new URL(req.url);
    const userId = url.searchParams.get("userId");
    const filterParam = url.searchParams.get("filter");

    if (!userId || !filterParam) {
      return Response.json({ error: "Missing required parameters" }, { status: 400 });
    }

    const keyPrefix = ["users", userId];
    const keys: string[] = [];

    // Dynamically build keys based on the filter parameter
    for await (const entry of kv.list<string>({ prefix: keyPrefix })) {
      if (entry.key[2].includes(filterParam)) {
        keys.push(entry.key.join(","));
      }
    }

    return Response.json({ keys });
  }

  return Response.json({ error: "Invalid request method" }, { status: 405 });
});